   142→		let previous = previousRegions[previousRegions.length - 1];
   143→		if (indent === -1) {
   144→			if (offSide) {
   145→				// for offSide languages, empty lines are associated to the previous block
   146→				// note: the next block is already written to the results, so this only
   147→				// impacts the end position of the block before
   148→				previous.endAbove = line;
   149→			}
   150→			continue; // only whitespace
   151→		}
   152→		let m;
   153→		if (pattern && (m = lineContent.match(pattern))) {
   154→			// folding pattern match
   155→			if (m[1]) { // start pattern match
   156→				// discard all regions until the folding pattern
   157→				let i = previousRegions.length - 1;
   158→				while (i > 0 && previousRegions[i].indent !== -2) {
   159→					i--;
   160→				}
   161→				if (i > 0) {
   162→					previousRegions.length = i + 1;
   163→					previous = previousRegions[i];
   164→
   165→					// new folding range from pattern, includes the end line
   166→					result.insertFirst(line, previous.line, indent);
   167→					previous.line = line;
   168→					previous.indent = indent;
   169→					previous.endAbove = line;
   170→					continue;
   171→				} else {
   172→					// no end marker found, treat line as a regular line
   173→				}
   174→			} else { // end pattern match
   175→				previousRegions.push({ indent: -2, endAbove: line, line });
   176→				continue;
   177→			}
   178→		}
   179→		if (previous.indent > indent) {
   180→			// discard all regions with larger indent
   181→			do {
   182→				previousRegions.pop();
   183→				previous = previousRegions[previousRegions.length - 1];
   184→			} while (previous.indent > indent);
   185→
   186→			// new folding range
   187→			const endLineNumber = previous.endAbove - 1;
   188→			if (endLineNumber - line >= 1) { // needs at east size 1
   189→				result.insertFirst(line, endLineNumber, indent);
   190→			}
   191→		}
   192→		if (previous.indent === indent) {
   193→			previous.endAbove = line;
   194→		} else { // previous.indent < indent
   195→			// new region with a bigger indent
   196→			previousRegions.push({ indent, endAbove: line, line });
   197→		}
   198→	}
   199→	return result.toIndentRanges(model);
   200→}
