    78→					}
    79→				}
    80→			}
    81→		}, onUnexpectedExternalError);
    82→	});
    83→	return Promise.all(promises).then(_ => {
    84→		return rangeData;
    85→	});
    86→}
    87→
    88→class RangesCollector {
    89→	private readonly _startIndexes: number[];
    90→	private readonly _endIndexes: number[];
    91→	private readonly _nestingLevels: number[];
    92→	private readonly _nestingLevelCounts: number[];
    93→	private readonly _types: Array<string | undefined>;
    94→	private _length: number;
    95→	private readonly _foldingRangesLimit: FoldingLimitReporter;
    96→
    97→	constructor(foldingRangesLimit: FoldingLimitReporter) {
    98→		this._startIndexes = [];
    99→		this._endIndexes = [];
   100→		this._nestingLevels = [];
   101→		this._nestingLevelCounts = [];
   102→		this._types = [];
   103→		this._length = 0;
   104→		this._foldingRangesLimit = foldingRangesLimit;
   105→	}
   106→
   107→	public add(startLineNumber: number, endLineNumber: number, type: string | undefined, nestingLevel: number) {
   108→		if (startLineNumber > MAX_LINE_NUMBER || endLineNumber > MAX_LINE_NUMBER) {
   109→			return;
   110→		}
   111→		const index = this._length;
   112→		this._startIndexes[index] = startLineNumber;
   113→		this._endIndexes[index] = endLineNumber;
   114→		this._nestingLevels[index] = nestingLevel;
   115→		this._types[index] = type;
   116→		this._length++;
   117→		if (nestingLevel < 30) {
   118→			this._nestingLevelCounts[nestingLevel] = (this._nestingLevelCounts[nestingLevel] || 0) + 1;
   119→		}
   120→	}
   121→
   122→	public toIndentRanges() {
   123→		const limit = this._foldingRangesLimit.limit;
   124→		if (this._length <= limit) {
   125→			this._foldingRangesLimit.update(this._length, false);
   126→
   127→			const startIndexes = new Uint32Array(this._length);
   128→			const endIndexes = new Uint32Array(this._length);
   129→			for (let i = 0; i < this._length; i++) {
   130→				startIndexes[i] = this._startIndexes[i];
   131→				endIndexes[i] = this._endIndexes[i];
   132→			}
   133→			return new FoldingRegions(startIndexes, endIndexes, this._types);
   134→		} else {
   135→			this._foldingRangesLimit.update(this._length, limit);
   136→
   137→			let entries = 0;
   138→			let maxLevel = this._nestingLevelCounts.length;
   139→			for (let i = 0; i < this._nestingLevelCounts.length; i++) {
   140→				const n = this._nestingLevelCounts[i];
   141→				if (n) {
   142→					if (n + entries > limit) {
   143→						maxLevel = i;
   144→						break;
   145→					}
   146→					entries += n;
   147→				}
   148→			}
   149→
   150→			const startIndexes = new Uint32Array(limit);
   151→			const endIndexes = new Uint32Array(limit);
   152→			const types: Array<string | undefined> = [];
   153→			for (let i = 0, k = 0; i < this._length; i++) {
   154→				const level = this._nestingLevels[i];
   155→				if (level < maxLevel || (level === maxLevel && entries++ < limit)) {
   156→					startIndexes[k] = this._startIndexes[i];
   157→					endIndexes[k] = this._endIndexes[i];
   158→					types[k] = this._types[i];
   159→					k++;
   160→				}
   161→			}
   162→			return new FoldingRegions(startIndexes, endIndexes, types);
   163→		}
   164→
   165→	}
   166→
   167→}
   168→
   169→export function sanitizeRanges(rangeData: IFoldingRangeData[], foldingRangesLimit: FoldingLimitReporter): FoldingRegions {
   170→	const sorted = rangeData.sort((d1, d2) => {
   171→		let diff = d1.start - d2.start;
   172→		if (diff === 0) {
   173→			diff = d1.rank - d2.rank;
   174→		}
   175→		return diff;
   176→	});
   177→	const collector = new RangesCollector(foldingRangesLimit);
   178→
   179→	let top: IFoldingRangeData | undefined = undefined;
   180→	const previous: IFoldingRangeData[] = [];
   181→	for (const entry of sorted) {
   182→		if (!top) {
   183→			top = entry;
   184→			collector.add(entry.start, entry.end, entry.kind && entry.kind.value, previous.length);
   185→		} else {
   186→			if (entry.start > top.start) {
   187→				if (entry.end <= top.end) {
   188→					previous.push(top);
   189→					top = entry;
   190→					collector.add(entry.start, entry.end, entry.kind && entry.kind.value, previous.length);
   191→				} else {
   192→					if (entry.start > top.end) {
   193→						do {
   194→							top = previous.pop();
   195→						} while (top && entry.start > top.end);
   196→						if (top) {
   197→							previous.push(top);
   198→						}
   199→						top = entry;
   200→					}
   201→					collector.add(entry.start, entry.end, entry.kind && entry.kind.value, previous.length);
   202→				}
   203→			}
   204→		}
   205→	}
   206→	return collector.toIndentRanges();
   207→}
