1→/*---------------------------------------------------------------------------------------------
     2→ *  Copyright (c) Microsoft Corporation. All rights reserved.
     3→ *  Licensed under the MIT License. See License.txt in the project root for license information.
     4→ *--------------------------------------------------------------------------------------------*/
     5→
     6→import { CancellationToken } from '../../../../base/common/cancellation.js';
     7→import { ITextModel } from '../../../common/model.js';
     8→import { FoldingRegions, MAX_LINE_NUMBER } from './foldingRanges.js';
     9→import { FoldingLimitReporter, RangeProvider } from './folding.js';
    10→
    11→const ID_NAMED_REGION_PROVIDER = 'namedRegion';
    12→
    13→export interface NamedRegion {
    14→	name: string;
    15→	startLineNumber: number;
    16→	endLineNumber: number;
    17→}
    18→
    19→export class NamedRegionRangeProvider implements RangeProvider {
    20→	readonly id = ID_NAMED_REGION_PROVIDER;
    21→
    22→	private namedRegions: NamedRegion[] = [];
    23→
    24→	constructor(
    25→		private readonly editorModel: ITextModel,
    26→		private readonly foldingRangesLimit: FoldingLimitReporter
    27→	) { }
    28→
    29→	dispose() { }
    30→
    31→	compute(cancelationToken: CancellationToken): Promise<FoldingRegions | null> {
    32→		return Promise.resolve(this.computeNamedRegions());
    33→	}
    34→
    35→	private computeNamedRegions(): FoldingRegions | null {
    36→		const lines = this.editorModel.getLineCount();
    37→		this.namedRegions = [];
    38→
    39→		// Stack to track open regions
    40→		const regionStack: Array<{ startLine: number; name: string }> = [];
    41→
    42→		// Regex to detect #region markers with optional whitespace and comments
    43→		const regionStartPattern = /^[\s]*(?:\/\/|#|\/\*|\*|--)\s*#region\s+(.+?)(?:\s*(?:\*\/|$))?/;
    44→		const regionEndPattern = /^[\s]*(?:\/\/|#|\/\*|\*|--)\s*#endregion/;
    45→
    46→		for (let lineNumber = 1; lineNumber <= lines; lineNumber++) {
    47→			const lineContent = this.editorModel.getLineContent(lineNumber);
    48→
    49→			// Check for region start
    50→			const startMatch = lineContent.match(regionStartPattern);
    51→			if (startMatch) {
    52→				const name = startMatch[1].trim();
    53→				regionStack.push({ startLine: lineNumber, name });
    54→				continue;
    55→			}
    56→
    57→			// Check for region end
    58→			if (regionEndPattern.test(lineContent)) {
    59→				if (regionStack.length > 0) {
    60→					const region = regionStack.pop();
    61→					if (region) {
    62→						this.namedRegions.push({
    63→							name: region.name,
    64→							startLineNumber: region.startLine,
    65→							endLineNumber: lineNumber
    66→						});
    67→					}
    68→				}
    69→				continue;
    70→			}
    71→		}
    72→
    73→		// Handle unclosed regions by closing them at end of file
    74→		while (regionStack.length > 0) {
    75→			const region = regionStack.pop();
    76→			if (region) {
    77→				this.namedRegions.push({
    78→					name: region.name,
    79→					startLineNumber: region.startLine,
    80→					endLineNumber: lines
    81→				});
    82→			}
    83→		}
    84→
    85→		// Sort by start line number
