import { CancellationToken } from '../../../../base/common/cancellation.js';
import { ITextModel } from '../../../common/model.js';
import { FoldingRegions, MAX_LINE_NUMBER } from './foldingRanges.js';
import { FoldingLimitReporter, RangeProvider } from './folding.js';

const ID_NAMED_REGION_PROVIDER = 'namedRegion';

export interface NamedRegion {
	name: string;
	startLineNumber: number;
	endLineNumber: number;
}

export class NamedRegionRangeProvider implements RangeProvider {
	readonly id = ID_NAMED_REGION_PROVIDER;

	private namedRegions: NamedRegion[] = [];

	constructor(
		private readonly editorModel: ITextModel,
		private readonly foldingRangesLimit: FoldingLimitReporter
	) { }

	dispose() { }

	compute(cancelationToken: CancellationToken): Promise<FoldingRegions | null> {
		return Promise.resolve(this.computeNamedRegions());
	}

	private computeNamedRegions(): FoldingRegions | null {
		const lines = this.editorModel.getLineCount();
		this.namedRegions = [];

		// Stack to track open regions
		const regionStack: Array<{ startLine: number; name: string }> = [];

		// Regex to detect #region markers with optional whitespace and comments
		const regionStartPattern = /^[\s]*(?:\/\/|#|\/\*|\*|--)\s*#region\s+(.+?)(?:\s*(?:\*\/|$))?/;
		const regionEndPattern = /^[\s]*(?:\/\/|#|\/\*|\*|--)\s*#endregion/;

		for (let lineNumber = 1; lineNumber <= lines; lineNumber++) {
			const lineContent = this.editorModel.getLineContent(lineNumber);

			// Check for region start
			const startMatch = lineContent.match(regionStartPattern);
			if (startMatch) {
				const name = startMatch[1].trim();
				regionStack.push({ startLine: lineNumber, name });
				continue;
			}

			// Check for region end
			if (regionEndPattern.test(lineContent)) {
				if (regionStack.length > 0) {
					const region = regionStack.pop();
					if (region) {
						this.namedRegions.push({
							name: region.name,
							startLineNumber: region.startLine,
							endLineNumber: lineNumber
						});
					}
				}
				continue;
			}
		}

		// Handle unclosed regions by closing them at end of file
		while (regionStack.length > 0) {
			const region = regionStack.pop();
			if (region) {
				this.namedRegions.push({
					name: region.name,
					startLineNumber: region.startLine,
					endLineNumber: lines
				});
			}
		}

		// Sort by start line number
		this.namedRegions.sort((a, b) => a.startLineNumber - b.startLineNumber);

		// Convert to FoldingRegions format
		return this.createFoldingRegions();
	}

	private createFoldingRegions(): FoldingRegions | null {
		if (this.namedRegions.length === 0) {
			return null;
		}

		const limit = this.foldingRangesLimit.limit;
		const regionsToUse = this.namedRegions.slice(0, limit);

		const startIndexes = new Uint32Array(regionsToUse.length);

